            "grocery" => 1,
            "pharmacy" => 2,
            "restaurant" => 3,
            _ => panic!("Invalid business line"),
        };
        valid.push((priority, c.clone()));
    }
    valid.sort_by(|a, b| a.0.cmp(&b.0).then(a.1.cmp(&b.1)));
